import sys

class Node:
    def __init__(self, data):
        self.data = data
        self.prev = None
        self.next = None

class Solution:
    def deleteAll(self, head: Node, key: int) -> Node:
        cur = head
        while cur:
            nxt = cur.next
            if cur.data == key:
                # unlink cur
                if cur.prev:
                    cur.prev.next = cur.next
                else:
                    head = cur.next
                if cur.next:
                    cur.next.prev = cur.prev
            cur = nxt
        return head

if __name__ == '__main__':
    data = sys.stdin.read().split()
    if not data:
        sys.exit(0)
    it = iter(data)
    n = int(next(it))
    values = [int(next(it)) for _ in range(n)]
    key = int(next(it))
    # build doubly linked list
    head = None
    prev = None
    for v in values:
        node = Node(v)
        if not head:
            head = node
        else:
            prev.next = node
            node.prev = prev
        prev = node
    sol = Solution()
    new_head = sol.deleteAll(head, key)
    # collect result
    res = []
    cur = new_head
    while cur:
        res.append(cur.data)
        cur = cur.next
    print(len(res))
    for val in res:
        print(val)

