#include <bits/stdc++.h>
using namespace std;

struct Node {
    int data;
    Node* prev;
    Node* next;
    Node(int d) : data(d), prev(nullptr), next(nullptr) {}
};

class Solution {
public:
    Node* deleteAll(Node* head, int key) {
        Node* cur = head;
        while (cur) {
            Node* nxt = cur->next;
            if (cur->data == key) {
                if (cur->prev) cur->prev->next = cur->next;
                else head = cur->next;
                if (cur->next) cur->next->prev = cur->prev;
                // optional: delete cur;
            }
            cur = nxt;
        }
        return head;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    int key; cin >> key;
    // build doubly linked list
    Node* head = nullptr;
    Node* prev = nullptr;
    for (int v : vals) {
        Node* node = new Node(v);
        if (!head) head = node;
        else {
            prev->next = node;
            node->prev = prev;
        }
        prev = node;
    }
    Solution sol;
    Node* newHead = sol.deleteAll(head, key);
    // output
    vector<int> out;
    for (Node* cur = newHead; cur; cur = cur->next) out.push_back(cur->data);
    cout << out.size() << "\n";
    for (int v : out) cout << v << "\n";
    return 0;
}
